function daysBetween(d1, d2) {
  return Math.ceil((d2 - d1) / (1000 * 60 * 60 * 24));
}

function buildCard(post) {
  // No URL = not written yet, always plain coming soon regardless of date
  if (!post.url) {
    return `<article class="post-card coming-soon">
      <div class="post-card-body">
        <span class="post-tag" style="background:rgba(107,114,128,.1);color:var(--gray);">${post.tag}</span>
        <h2>${post.title}</h2>
        <div class="post-meta">By <strong>Joe Deal</strong> · Coming Soon</div>
        <p class="post-excerpt">${post.excerpt}</p>
        <span class="coming-soon-label">Coming Soon</span>
      </div>
    </article>`;
  }

  const now = new Date();
  now.setHours(0,0,0,0);
  const pubDate = new Date(post.published);
  pubDate.setHours(0,0,0,0);
  const isLive   = pubDate <= now;
  const daysLeft = isLive ? 0 : daysBetween(now, pubDate);

  if (isLive) {
    // Live card
    return `<article class="post-card">
      <div class="post-card-body">
        <span class="post-tag">${post.tag}</span>
        <h2><a href="${post.url}">${post.title}</a></h2>
        <div class="post-meta">${post.meta}</div>
        <p class="post-excerpt">${post.excerpt}</p>
        <a href="${post.url}" class="post-read-more">Read Article →</a>
      </div>
    </article>`;
  } else {
    // Scheduled countdown card
    return `<article class="post-card coming-soon" style="opacity:.8;">
      <div class="post-card-body">
        <span class="post-tag">${post.tag}</span>
        <h2>${post.title}</h2>
        <div class="post-meta" style="color:#e8720c;font-weight:700;">🔒 Unlocks in ${daysLeft} day${daysLeft!==1?'s':''}</div>
        <p class="post-excerpt">${post.excerpt}</p>
        <div style="display:flex;align-items:center;gap:10px;flex-wrap:wrap;">
          <span class="coming-soon-label">Coming ${pubDate.toLocaleDateString('en-US',{month:'long',day:'numeric'})}</span>
          <span id="countdown-${post.published}" style="font-size:.78rem;color:var(--gray);font-weight:600;font-family:'Montserrat',sans-serif;"></span>
        </div>
      </div>
    </article>`;
  }
}

function renderPosts() {
  const grid = document.getElementById('blog-posts-grid');
  if (!grid) return;
  // Homeowner blog — filter out any posts flagged for contractor audience.
  // Contractor-audience posts stay in the POSTS array for a future NBD Pro blog.
  const homeownerPosts = POSTS.filter(p => p.audience !== 'contractor');
  grid.innerHTML = homeownerPosts.map(buildCard).join('');
  // Mark the first live (non-coming-soon) post as featured so it reads as the headline.
  var firstLive = grid.querySelector('.post-card:not(.coming-soon)');
  if (firstLive) firstLive.classList.add('featured');
  startCountdowns();
}

function startCountdowns() {
  POSTS.forEach(post => {
    const el = document.getElementById('countdown-' + post.published);
    if (!el) return;
    // Skip far-future placeholder dates
    if (new Date(post.published).getFullYear() >= 2099) return;
    function tick() {
      const pub = new Date(post.published);
      pub.setHours(0,0,0,0);
      const diff = pub - new Date();
      if (diff <= 0) { location.reload(); return; }
      const d = Math.floor(diff/86400000);
      const h = Math.floor((diff%86400000)/3600000);
      const m = Math.floor((diff%3600000)/60000);
      el.textContent = d + 'd ' + h + 'h ' + m + 'm remaining';
      setTimeout(tick, 60000);
    }
    tick();
  });
}

// Script is at bottom of page — DOM already ready, call directly
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', renderPosts);
} else {
  renderPosts();
}
